// httpsFetch shim — function-node sandbox lacks global fetch. Uses Node stdlib.
function httpsFetch(urlStr, opts = {}) {
  return new Promise((resolve, reject) => {
    let parsed;
    try { parsed = new urlmod.URL(urlStr); }
    catch (e) { return reject(new Error('bad URL: ' + urlStr)); }
    const isHttps = parsed.protocol === 'https:';
    const lib = isHttps ? https : http;
    const body = opts.body;
    const headers = Object.assign({}, opts.headers || {});
    if (body && !headers['Content-Length']) headers['Content-Length'] = Buffer.byteLength(body);
    const req = lib.request({
      method: opts.method || 'GET',
      hostname: parsed.hostname,
      port: parsed.port || (isHttps ? 443 : 80),
      path: parsed.pathname + (parsed.search || ''),
      headers,
      timeout: opts.timeoutMs || 5000,
      rejectUnauthorized: opts.rejectUnauthorized !== false
    }, (res) => {
      let data = '';
      res.on('data', (c) => { data += c; });
      res.on('end', () => resolve({
        ok: res.statusCode >= 200 && res.statusCode < 300,
        status: res.statusCode,
        headers: res.headers,
        text: () => Promise.resolve(data),
        json: () => { try { return Promise.resolve(JSON.parse(data)); } catch (e) { return Promise.reject(e); } }
      }));
    });
    req.on('error', reject);
    req.on('timeout', () => { req.destroy(new Error('timeout')); });
    if (body) req.write(body);
    req.end();
  });
}

const probes = [];
const trinoScheme = env.get('AI_INSIGHT_TRINO__HTTP_SCHEME') || 'https';
const trinoHost   = env.get('AI_INSIGHT_TRINO__HOST');
const trinoPort   = env.get('AI_INSIGHT_TRINO__PORT') || 8443;
const nifiBase    = env.get('FACIS_NIFI_BASE') || 'https://212.132.83.82:8443';
const kafkaBoot   = env.get('FACIS_KAFKA_BROKERS') || env.get('DSP_KAFKA_BOOTSTRAP') || '';

// Node-RED function-node sandbox does not expose AbortController; fall back to
// a Promise.race timeout. fetch itself is available (Node.js >= 18).
function withTimeout(promise, ms) {
  return Promise.race([
    promise,
    new Promise((_, reject) => setTimeout(() => reject(new Error(`timeout ${ms}ms`)), ms))
  ]);
}

async function probe(name, url, opts = {}) {
  const start = Date.now();
  try {
    const res = await withTimeout(
      httpsFetch(url, { method: opts.method || 'GET', headers: opts.headers }),
      opts.timeoutMs || 3000
    );
    const ms = Date.now() - start;
    return { service: name, url, status: res.ok ? 'healthy' : 'degraded', http_status: res.status, latency_ms: ms };
  } catch (e) {
    return { service: name, url, status: 'unreachable', error: String(e.message || e), latency_ms: Date.now() - start };
  }
}

const tasks = [
  probe('orce',        'http://localhost:1880/api/v1/health'),
  probe('ai-insight',  'http://localhost:1880/api/v1/health',
        { headers: { 'x-agreement-id': 'integrations-probe', 'x-asset-id': 'facis-platform', 'x-user-roles': 'ai_insight_consumer' } })
];
if (trinoHost) {
  tasks.push(probe('trino', `${trinoScheme}://${trinoHost}:${trinoPort}/v1/info`));
}
tasks.push(probe('nifi',  `${nifiBase}/nifi-api/flow/about`));

const results = await Promise.all(tasks);

// Kafka: HTTP probe is not meaningful (TCP-only protocol). Report config
// presence + per-broker hint so the UI can render "configured" or "unconfigured".
const kafkaBrokers = kafkaBoot ? kafkaBoot.split(',').map(s => s.trim()).filter(Boolean) : [];
results.push({
  service: 'kafka',
  url: null,
  status: kafkaBrokers.length ? 'configured' : 'unconfigured',
  brokers: kafkaBrokers,
  broker_count: kafkaBrokers.length,
  latency_ms: null
});

const summary = {
  healthy:     results.filter(r => r.status === 'healthy').length,
  degraded:    results.filter(r => r.status === 'degraded').length,
  unreachable: results.filter(r => r.status === 'unreachable').length,
  configured:  results.filter(r => r.status === 'configured').length,
  total:       results.length
};

msg.headers = { 'Content-Type': 'application/json', 'Cache-Control': 'no-store' };
msg.statusCode = 200;
msg.payload = { generated_at: new Date().toISOString(), summary, services: results };
return msg;
